import{_ as o,C as l,o as n,c as s,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Luxembourg Healthcare","description":"Healthcare and HRT access for transgender people in Luxembourg","frontmatter":{"layout":"doc","title":"Luxembourg Healthcare","description":"Healthcare and HRT access for transgender people in Luxembourg"},"headers":[],"relativePath":"europe/luxembourg/healthcare.md","filePath":"europe/luxembourg/healthcare.md","lastUpdated":null}'),c={name:"europe/luxembourg/healthcare.md"};function h(u,e,p,g,m,b){const t=l("Badge");return n(),s("div",null,[r(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[i("Informed Consent Model",-1)])]),_:1}),r(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[i("Public Healthcare System",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-luxembourg" tabindex="-1">Healthcare in Luxembourg <a class="header-anchor" href="#healthcare-in-luxembourg" aria-label="Permalink to &quot;Healthcare in Luxembourg&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Luxembourg provides gender affirming healthcare through its public healthcare system (Caisse Nationale de Santé - CNS). The primary centre for trans-specific healthcare is the <strong>Centre Hospitalier de Luxembourg (CHL)</strong>.</p><p>Healthcare is available in three official languages: Luxembourgish, French, and German. English is also spoken at major hospitals.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Luxembourg follows an informed consent model for hormone therapy. This means:</p><ul><li>No requirement for a psychological assessment or diagnosis of gender dysphoria</li><li>Patients can access hormone therapy after a consultation with an endocrinologist</li><li>Treatment is covered by the public health insurance system (CNS)</li><li>Typical wait times for an endocrinology appointment are 2-4 months</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>CHL - Gender Identity Clinic</td><td>Luxembourg City</td><td>HRT, psychological support, referrals</td><td>FR, DE, LU, EN</td><td>2-4 months</td></tr><tr><td>CHL - Endocrinology</td><td>Luxembourg City</td><td>Hormone therapy, monitoring</td><td>FR, DE, LU, EN</td><td>2-4 months</td></tr><tr><td>Hôpital Kirchberg</td><td>Luxembourg City</td><td>General endocrinology, HRT</td><td>FR, DE, LU, EN</td><td>3-5 months</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender affirming surgeries are covered by the CNS under certain conditions. Prior authorisation is required and typically involves a multidisciplinary assessment. Available surgeries include:</p><ul><li>Chest/breast surgery (top surgery)</li><li>Genital surgery (bottom surgery)</li><li>Facial feminisation surgery (selective coverage)</li><li>Voice surgery (limited coverage)</li></ul><p>Patients may also access surgical care in neighbouring countries (France, Belgium, Germany) under the EU cross-border healthcare directive.</p><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member state, Luxembourg accepts prescriptions from other EU/EEA countries under the Cross-Border Healthcare Directive (2011/24/EU). Visitors with EU prescriptions can fill them at Luxembourgish pharmacies. It is recommended to carry a physical copy of the prescription and a letter from the prescribing doctor.</p><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (CNS covered)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel)</td><td>~€5-15/month</td><td>Widely available</td></tr><tr><td>Testosterone (injectable/gel)</td><td>~€10-25/month</td><td>Widely available</td></tr><tr><td>Spironolactone</td><td>~€8-12/month</td><td>Available</td></tr><tr><td>Antiandrogens (Cyproterone)</td><td>~€10-20/month</td><td>Available</td></tr></tbody></table><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><p>Psychological support for gender identity issues is available through:</p><ul><li>CHL Psychiatry Department</li><li>Private psychologists specialising in gender identity</li><li>CIGALE support groups</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>CNS (Health Insurance)</strong> — <a href="https://cns.lu/" target="_blank" rel="noreferrer">cns.lu</a></li><li><strong>CHL - Gender Identity Clinic</strong> — <a href="https://www.chl.lu/" target="_blank" rel="noreferrer">chl.lu</a></li><li><strong>CIGALE</strong> — Support and advocacy: <a href="https://www.cigale.lu/" target="_blank" rel="noreferrer">cigale.lu</a></li></ul>',21))])}const x=o(c,[["render",h]]);export{f as __pageData,x as default};
